// SPDX-License-Identifier: MIT
pragma solidity ^0.8.0;

contract NextDateCalculator {
    
    // Check if a year is leap year
    function isLeapYear(uint year) internal pure returns (bool) {
        if ((year % 400 == 0) || (year % 4 == 0 && year % 100 != 0)) {
            return true;
        }
        return false;
    }
    
    // Get number of days in a month considering leap years
    function daysInMonth(uint month, uint year) internal pure returns (uint) {
        if (month == 1 || month == 3 || month == 5 || month == 7 || 
            month == 8 || month == 10 || month == 12) {
            return 31;
        } else if (month == 4 || month == 6 || month == 9 || month == 11) {
            return 30;
        } else if (month == 2) {
            if (isLeapYear(year)) {
                return 29;
            } else {
                return 28;
            }
        }
        return 0; // invalid month
    }
    
    // Calculate the next date
    function getNextDate(uint day, uint month, uint year) public pure returns (uint, uint, uint) {
        uint daysThisMonth = daysInMonth(month, year);
        require(daysThisMonth > 0, "Invalid month");
        require(day > 0 && day <= daysThisMonth, "Invalid day");
        
        day += 1;
        if (day > daysThisMonth) {
            day = 1;
            month += 1;
            if (month > 12) {
                month = 1;
                year += 1;
            }
        }
        
        return (day, month, year);
    }
}

